import osimport jsonimport pymysqlfrom dotenv import load_dotenvfrom typing import List, Dict, Tuplescript_dir = os.path.dirname(os.path.abspath(__file__))  # utils目录parent_dir = os.path.dirname(script_dir)  # 项目根目录output_path = os.path.join(parent_dir, "metadata", "ods_meta.json")def get_mysql_table_metadata(host: str, port: int, user: str, password: str, database: str, table_name: str) -> Dict:    """    从MySQL获取指定表的元数据信息    """    connection = pymysql.connect(        host=host,        port=port,        user=user,        password=password,        database=database,        charset='utf8mb4'    )    try:        with connection.cursor() as cursor:            # 查询列信息            column_query = """                SELECT                     column_name,                    data_type,                    is_nullable,                    column_default,                    column_comment,                    column_key                FROM information_schema.columns                 WHERE table_schema = %s AND table_name = %s                ORDER BY ordinal_position            """            cursor.execute(column_query, (database, table_name))            columns_info = cursor.fetchall()            # 构建列信息            columns = []            for col in columns_info:                column_name, data_type, is_nullable, default_value, comment, column_key = col                # 确定是否为主键                is_primary = column_key == 'PRI'                column_info = {                    "name": column_name,                    "type": data_type,                    "is_primary": is_primary                }                if comment:                    column_info["comment"] = comment                if default_value is not None:                    column_info["default"] = default_value                if is_nullable == 'YES':                    column_info["nullable"] = True                columns.append(column_info)            # 构建完整的元数据结构            metadata = {                f"ods_{database}_db_{table_name}": {                    "source": {                        "type": "mysql",                        "db": database,                        "table": table_name                    },                    "columns": columns                }            }            return metadata    finally:        connection.close()def get_all_tables_in_database(host: str, port: int, user: str, password: str, database: str) -> List[str]:    """    获取数据库中所有表的名称    """    connection = pymysql.connect(        host=host,        port=port,        user=user,        password=password,        database=database,        charset='utf8mb4'    )    try:        with connection.cursor() as cursor:            cursor.execute("SHOW TABLES")            tables = [row[0] for row in cursor.fetchall()]            return tables    finally:        connection.close()def generate_multiple_meta_from_env(db_table_pairs: List[Tuple[str, List[str]]]) -> Dict:    """    从环境变量读取MySQL配置，生成多个数据库和表的元数据JSON    db_table_pairs: [(database_name, [table1, table2, ...]), ...]    """    # 加载环境变量    load_dotenv()    # 从环境变量获取MySQL配置    mysql_host = os.environ.get('MYSQL_HOST', 'localhost')    mysql_port = int(os.environ.get('MYSQL_PORT', 3306))    mysql_user = os.environ.get('MYSQL_USER', 'root')    mysql_password = os.environ.get('MYSQL_PASSWORD', '')    # 验证必要配置    if not all([mysql_host, mysql_user, mysql_password]):        raise ValueError("缺少必要的MySQL连接配置")    # 合并所有元数据    all_metadata = {}    for database, tables in db_table_pairs:        if not tables:  # 如果表列表为空，获取数据库中所有表            tables = get_all_tables_in_database(mysql_host, mysql_port, mysql_user, mysql_password, database)        for table in tables:            try:                print(f"正在获取 {database}.{table} 的元数据...")                table_metadata = get_mysql_table_metadata(                    host=mysql_host,                    port=mysql_port,                    user=mysql_user,                    password=mysql_password,                    database=database,                    table_name=table                )                # 合并到总元数据中                all_metadata.update(table_metadata)            except Exception as e:                print(f"获取 {database}.{table} 元数据时出错: {e}")                continue  # 继续处理下一个表    return all_metadatadef generate_meta_from_config(config_file: str = "db_config.json") -> Dict:    """    从配置文件读取数据库表配置，生成元数据    配置文件格式示例:    {      "databases": [        {          "name": "order_db",          "tables": ["t_order", "t_order_item"]        },        {          "name": "user_db",          "tables": ["t_user", "t_profile"]        }      ]    }    """    # 加载配置文件    with open(config_file, 'r', encoding='utf-8') as f:        config = json.load(f)    db_table_pairs = []    for db_info in config['databases']:        database_name = db_info['name']        tables = db_info.get('tables', [])  # 如果tables为空，则获取所有表        db_table_pairs.append((database_name, tables))    return generate_multiple_meta_from_env(db_table_pairs)def save_meta_to_file(metadata: Dict, output_file_path: str):    """    将元数据保存到文件    """    with open(output_file_path, 'w', encoding='utf-8') as f:        json.dump(metadata, f, ensure_ascii=False, indent=4)    print(f"元数据已保存到: {output_file_path}")# 使用示例if __name__ == "__main__":    # 方式1: 直接指定数据库表对    db_table_pairs = [        ("sy_order_db", ["order", "order_item"]),        ("platform_user", ["user"])    ]    try:        # 生成元数据        meta_data = generate_multiple_meta_from_env(db_table_pairs)        # 打印元数据        print(json.dumps(meta_data, ensure_ascii=False, indent=2))        # 保存到文件        save_meta_to_file(meta_data, output_path)    except Exception as e:        print(f"生成元数据时出错: {e}")    print(output_path)    # 方式2: 从配置文件读取    # try:    #     meta_data = generate_meta_from_config("db_config.json")    #     save_meta_to_file(meta_data, "metadata/ods_meta.json")    # except FileNotFoundError:    #     print("配置文件 db_config.json 不存在")    # except Exception as e:    #     print(f"从配置文件生成元数据时出错: {e}")